const sourceItems = $input.all();

// split snapshot + action rows
const snapshot = sourceItems
  .filter(i => i.json && i.json.vacant_units !== undefined)
  .map(i => i.json);

const ops = $json.operational_tasks || [];

const opsHtml = ops.length
  ? ops.map(o => `
    <div style="margin-bottom:8px;">
      <b>${o.name}</b><br>
      Due: ${o.date} (${o.days_until} days)
    </div>
  `).join('')
  : '<div>No upcoming operational deadlines</div>';

const actions = sourceItems
  .filter(i => i.json && i.json.action_description !== undefined)
  .map(i => i.json);

// current meeting context
const meeting = $('Pass Through Meetings').item.json;

// clean subject date
const dt = new Date(meeting.meeting_datetime);
const formattedDate = dt.toLocaleString('en-US', {
  month: 'short',
  day: 'numeric',
  year: 'numeric',
  hour: 'numeric',
  minute: '2-digit'
});

// dedupe snapshot by property_name just in case
const snapshotMap = {};
for (const row of snapshot) {
  snapshotMap[row.property_name] = row;
}
const cleanSnapshot = Object.values(snapshotMap);

// build snapshot html
const snapshotHtml = cleanSnapshot.length
  ? cleanSnapshot.map(r => `
    <div style="margin-bottom:14px;">
      <strong style="font-size:15px;">${r.property_name}</strong>
      <hr style="border:none;border-top:1px solid #ddd;margin:6px 0;">
      Vacants: ${r.vacant_units}<br>
      Ready: ${r.ready_vacants}<br>
      Not Ready: ${r.not_ready_vacants}<br>
      Delinquent: <strong>${r.delinquent_count} / $${Number(r.delinquent_amount).toFixed(2)}</strong><br>
      Turns: ${r.turns_in_progress}<br>
      Work Orders &gt; 7 Days: ${r.work_orders_over_7_days}
    </div>
  `).join('')
  : '<div>No snapshot rows found</div>';

// build actions html
const actionsHtml = actions.length
  ? actions.map(a => `
    <div style="margin-bottom:14px;">
      <strong>${a.action_description}</strong><br>
      Owner: ${a.action_owner}<br>
      Due: ${a.due_date}<br>
      Status: ${a.status}${a.property_name ? `<br>Property: ${a.property_name}` : ''}
    </div>
  `).join('')
  : '<div>No prior actions found</div>';

// final body
const body = `
<div style="font-family: Arial, sans-serif; font-size: 14px; color: #000;">
  <p>Hi ${meeting.manager_name},</p>

  <p>
    In preparation for our upcoming meeting, here are the highlights and stats of last week and the action items that were discussed.
  </p>

  <h3 style="margin-top:20px;">Portfolio Snapshot</h3>
  ${snapshotHtml}

    <h3 style="margin-top:20px;">Upcoming Operational Deadlines</h3>
  ${opsHtml}

  <h3 style="margin-top:20px;">Prior Action Items</h3>
  ${actionsHtml}

  <p style="margin-top:20px;">
    Please be prepared to provide updates on all open items and any material changes since the Monday baseline.
  </p>

  <p>- Brandon</p>
</div>
`;

return [{
  json: {
    meeting_id: meeting.meeting_id,
    manager_name: meeting.manager_name,
    subject: `Weekly Review – ${meeting.manager_name} – ${formattedDate}`,
    body
  }
}];

function makeUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const source = $('Build Email').item.json;
return [{
  json: {
    id: makeUuid(),
    manager_name: source.manager_name,
    meeting_id: source.meeting_id,
    email_sent_timestamp: new Date().toISOString().slice(0,19).replace('T',' '),
    email_status: 'sent',
    created_at: new Date().toISOString().slice(0,19).replace('T',' ')
  }
}];

