const meeting = $json;

// participants passed from upstream (or empty)
const participants = meeting.participants || [];

/*
  HARD SOURCE OF TRUTH
  This should grow over time
*/
const directory = {
  "Brandon Stewart": "brandon@blazeproperty.com",
  "Tammie Stewart": "tammie@blazeproperty.com",
  "Nicole Baker": "nicoleb@blazeproperty.com",
  "Amy": "amy@blazeproperty.com",
  "Breanna": "breanna@blazeproperty.com",
  "Debbie": "debbie@blazeproperty.com",
  "Dede": "dede@blazeproperty.com",
  "Shelbie": "shelbie@blazeproperty.com",
  "Chris": "chris@blazeproperty.com",
  "Ashlie": "ashlie@blazeproperty.com"
};

/*
  ALWAYS INCLUDED
*/
const required = [
  "brandon@blazeproperty.com",
  "tammie@blazeproperty.com", 
  "nicoleb@blazeproperty.com"
];

/*
  Resolve participants
*/
const resolved = [];

for (const p of participants) {
  if (!p) continue;

  const value = String(p).trim();

  // If already email → keep
  if (value.includes('@')) {
    resolved.push(value.toLowerCase());
    continue;
  }

  // If name → map
  if (directory[value]) {
    resolved.push(directory[value]);
  }
}

/*
  Fallback: include manager if nothing resolved
*/
if (resolved.length === 0 && meeting.manager_name) {
  const fallback = directory[meeting.manager_name];
  if (fallback) resolved.push(fallback);
}

/*
  Final recipient list
*/
const recipients = [
  ...new Set([
    ...required,
    ...resolved
  ])
];

return [{
  json: {
    ...meeting,
    recipients
  }
}];

const meeting = $('Pass Through Meetings').item.json;
const meetingDate = new Date(meeting.meeting_datetime);

const holidayRows = $('Fetch Operational Holidays').all().map(i => i.json);

const blazeHolidaySet = new Set(
  holidayRows
    .filter(h => h.calendar_type === 'blaze')
    .map(h => h.holiday_date)
);

const governmentHolidaySet = new Set(
  holidayRows
    .filter(h => h.calendar_type === 'government')
    .map(h => h.holiday_date)
);

function toDateOnlyString(date) {
  return date.toISOString().slice(0, 10);
}

function isWeekend(date) {
  return date.getDay() === 0 || date.getDay() === 6;
}

function isHoliday(date, calendarType) {
  const key = toDateOnlyString(date);
  if (calendarType === 'government') return governmentHolidaySet.has(key);
  return blazeHolidaySet.has(key);
}

function nextBusinessDay(date, calendarType) {
  const d = new Date(date);

  while (isWeekend(d) || isHoliday(d, calendarType)) {
    d.setDate(d.getDate() + 1);
  }

  return d;
}

function buildDate(year, monthIndex, day) {
  return new Date(year, monthIndex, day);
}

const tasks = [
  { name: 'Rent Due', day: 1, calendar_type: 'blaze' },
  { name: 'Late Notices', day: 5, calendar_type: 'blaze' },
  { name: 'Evictions Filed', day: 10, calendar_type: 'government' }
];

const currentYear = meetingDate.getFullYear();
const currentMonth = meetingDate.getMonth();

const nextMonthDate = new Date(currentYear, currentMonth + 1, 1);
const nextYear = nextMonthDate.getFullYear();
const nextMonth = nextMonthDate.getMonth();

const candidates = [];

for (const task of tasks) {
  candidates.push({
    ...task,
    due_date: nextBusinessDay(
      buildDate(currentYear, currentMonth, task.day),
      task.calendar_type
    )
  });

  candidates.push({
    ...task,
    due_date: nextBusinessDay(
      buildDate(nextYear, nextMonth, task.day),
      task.calendar_type
    )
  });
}

const upcoming = [];

for (const task of candidates) {
  const diffMs = task.due_date - meetingDate;
  const diffDays = Math.ceil(diffMs / (1000 * 60 * 60 * 24));

  if (diffDays >= 0 && diffDays <= 7) {
    upcoming.push({
      name: task.name,
      date: toDateOnlyString(task.due_date),
      days_until: diffDays,
      calendar_type: task.calendar_type
    });
  }
}

const seen = new Set();
const deduped = upcoming.filter(task => {
  const key = `${task.name}|${task.date}|${task.calendar_type}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return [{
  json: {
    ...$json,
    operational_tasks: deduped
  }
}];

